// Import Web3 from web3.js or Ethers.js 
const Web3 = require('web3');

let web3;
if (typeof window.ethereum !== 'undefined') { // If Metamask is installed, use its provider for connection to the network
    web3 = new Web3(window.ethereum);
} else if (window.web3) { 
    web3 = new Web3(window.web3.currentProvider);
} else {  
    web3 = new Web3(new Web3.providers.HttpProvider('https://localhost:8545')); // Fallback to localhost for development
}

// Private keys are kept in environment variables or secure secret storage systems
const privateKey = process.env.PRIVATE_KEY; 

async function sendTransaction(to, value) {
    const account = web3.eth.accounts.privateKeyToAccount(privateKey); // Create an Ethereumjs Account object using the user's private key
    web3.eth.accounts.wallet.add(account);  // Add this account to the wallet, so it can sign transactions
    
    const tx = {
        to: to,
        value: web3.utils.toWei(value, 'ether'),   // Convert ETH amount from "Ether" units to Wei for blockchain transaction (1 ETH = 1e18 Wei)
        gas: 21000   // Gas limit in Gwei
    };
    
    const signedTx = await web3.eth.accounts.signTransaction(tx, privateKey);  // Sign the transaction with the user's private key
    
    return web3.eth.sendSignedTransaction(signedTx.rawTransaction)   // Broadcast the signed transaction to the network
}

async function callContractFunction(contractAddress, contractAbi, methodName, ...args) {
    const contract = new web3.eth.Contract(contractAbi, contractAddress);  // Create a Contract instance at a specific address using the given ABI
    
    return await contract.methods[methodName](...args).call();   // Call the method with provided arguments on the smart contract and fetch the result
}